// Supabase sends payload as body - normalize for Switch node
const body = $input.first().json.body || $input.first().json;
const record = body.record || {};
const table = body.table || 'unknown';

return {
  json: {
    table,
    record,
    type: body.type,
    schema: body.schema
  }
};

// Build Resend API payloads for waitlist_signups
const r = $input.first().json.record;
const isFounding = r.is_founding_member === true;
const name = r.name || r.email?.split('@')[0] || 'there';
const email = r.email || '';

const htmlUser = isFounding
  ? `<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{background:#0f0a1a;color:#f5f5f5;font-family:-apple-system,sans-serif;margin:0;padding:24px}.card{background:rgba(255,255,255,0.05);border-radius:12px;padding:24px}h1{font-size:24px}p{margin:0 0 12px;line-height:1.6;color:#a0a0a0}.accent{color:#a855f7}</style></head><body><div class="card"><h1>You're in, ${name}</h1><p>Welcome to the founding circle. We'll send your activation link to <strong>${email}</strong>.</p><ul><li>50 credits on activation</li><li>Founding Member badge — permanent</li><li>1 month free, then €6.99/month forever</li></ul><p class="accent">— The waQup team</p></div></body></html>`
  : `<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{background:#0f0a1a;color:#f5f5f5;font-family:-apple-system,sans-serif;margin:0;padding:24px}.card{background:rgba(255,255,255,0.05);border-radius:12px;padding:24px}h1{font-size:24px}p{margin:0 0 12px;line-height:1.6;color:#a0a0a0}.accent{color:#a855f7}</style></head><body><div class="card"><h1>You're on the list</h1><p>Hi ${name},</p><p>Thanks for joining the waQup waitlist. We'll reach out when we're ready for you.</p><p class="accent">— The waQup team</p></div></body></html>`;

const subject = isFounding ? 'Welcome to waQup Founding Members' : "You're on the waQup waitlist";
const recordSummary = JSON.stringify(r, null, 2);
const teamHtml = `<h2>New waitlist_signups</h2><pre>${recordSummary}</pre><p><small>${new Date().toISOString()}</small></p>`;

return { json: {
  userPayload: email ? { from: 'waQup <hello@waqup.com>', to: [email], subject, html: htmlUser } : null,
  teamPayload: { from: 'waQup <hello@waqup.com>', to: ['ops@waqup.com'], subject: `[waQup] New waitlist — ${name || email}`, html: teamHtml }
} };

