const teamHtml = `<h2>New feedback</h2><pre>${recordSummary}</pre><p><small>${new Date().toISOString()}</small></p>`;

return { json: {
  userPayload: null,
  teamPayload: { from: 'waQup <hello@waqup.com>', to: ['support@waqup.com'], subject: `[waQup] New feedback — ${r.category || 'general'}`, html: teamHtml }
